module packet_filter(
    input [15:0] filtered_packet,
    output reg allow
);
    always @(*) begin
        if (filtered_packet == 16'b1010101010101010 || filtered_packet == 16'b1111000011110000) begin
            allow = 1;
        end else begin
            allow = 0;
        end
    end
endmodule
